@router.get("/customer/rewards", response_model=CustomerRewardsResponse)
async def get_customer_rewards(current_user = Depends(get_current_user)):
    """Get detailed customer rewards, tier status, and benefits"""
    db = get_db()

    # Fetch from database
    account = await db.customer_reward_accounts.find_one({
        "customer_id": str(current_user.id)
    })

    if not account:
        # Get referral code if exists
        code_record = await db.referral_codes.find_one({
            "user_id": str(current_user.id),
            "referral_type": ReferralType.CUSTOMER.value
        })
        referral_code = code_record["code"] if code_record else "IH-C-NONE"

        return CustomerRewardsResponse(
            referral_code=referral_code,
            tier="bronze",
            hashi_coins_balance=0,
            total_referrals=0,
            free_delivery_credits=0,
            discount_credits=0.0,
            tier_progress={
                "current_tier": "Bronze",
                "referrals_to_next_tier": 1,
                "next_tier": "Silver"
            },
            tier_benefits=CustomerRewardAccount.get_tier_benefits(CustomerTier.BRONZE)
        )

    # Calculate tier progress
    completed = account.get("completed_referrals", 0)
    current_tier = account.get("tier", "bronze")

    tier_thresholds = {
        "bronze": {"min": 1, "next": "silver", "next_min": 6},
        "silver": {"min": 6, "next": "gold", "next_min": 16},
        "gold": {"min": 16, "next": "platinum", "next_min": 51},
        "platinum": {"min": 51, "next": None, "next_min": None}
    }

    tier_info = tier_thresholds.get(current_tier, tier_thresholds["bronze"])
    next_tier = tier_info["next"]
    referrals_to_next = max(0, tier_info["next_min"] - completed) if tier_info["next_min"] else 0

    return CustomerRewardsResponse(
        referral_code=account.get("referral_code", "IH-C-NONE"),
        tier=current_tier,
        hashi_coins_balance=account.get("hashi_coins_balance", 0),
        total_referrals=account.get("total_referrals", 0),
        free_delivery_credits=account.get("free_delivery_credits", 0),
        discount_credits=account.get("discount_credits", 0.0),
        tier_progress={
            "current_tier": current_tier.capitalize(),
            "referrals_to_next_tier": referrals_to_next,
            "next_tier": next_tier.capitalize() if next_tier else None,
            "completed_referrals": completed
        },
        tier_benefits=CustomerRewardAccount.get_tier_benefits(CustomerTier(current_tier))
    )


@router.post("/redeem/free-delivery")
async def redeem_free_delivery(current_user = Depends(get_current_user)):
    """Redeem Hashi Coins for a free delivery"""
    db = get_db()
    rewards = ReferralReward(referral_type=ReferralType.CUSTOMER)

    # Fetch user's reward account
    account = await db.customer_reward_accounts.find_one({
        "customer_id": str(current_user.id)
    })

    if not account:
        raise HTTPException(status_code=404, detail="Reward account not found")

    current_balance = account.get("hashi_coins_balance", 0)
    coins_required = rewards.coins_for_free_delivery

    # Check if user has enough coins
    if current_balance < coins_required:
        return {
            "message": f"You need {coins_required} Hashi Coins for free delivery",
            "coins_required": coins_required,
            "current_balance": current_balance,
            "can_redeem": False
        }

    # Deduct coins and add free delivery credit
    new_balance = current_balance - coins_required

    await db.customer_reward_accounts.update_one(
        {"customer_id": str(current_user.id)},
        {
            "$inc": {
                "hashi_coins_balance": -coins_required,
                "total_coins_spent": coins_required,
                "free_delivery_credits": 1
            },
            "$set": {"updated_at": datetime.utcnow()}
        }
    )

    # Create coin transaction
    txn = CoinTransaction(
        customer_id=str(current_user.id),
        amount=-coins_required,
        transaction_type="redemption",
        description="Redeemed for free delivery",
        balance_after=new_balance
    )
    await db.coin_transactions.insert_one(txn.dict())

    # Create redemption record
    redemption = RewardRedemption(
        customer_id=str(current_user.id),
        redemption_type="free_delivery",
        coins_spent=coins_required,
        value_zar=10.0,  # Approximate delivery value
        expires_at=datetime.utcnow() + timedelta(days=30)
    )
    await db.reward_redemptions.insert_one(redemption.dict())

    return {
        "message": "Free delivery redeemed successfully!",
        "coins_required": coins_required,
        "current_balance": new_balance,
        "can_redeem": True,
        "free_delivery_credits": account.get("free_delivery_credits", 0) + 1,
        "redemption_id": redemption.id
    }


