                    balance_after=new_balance
                )
                await db.coin_transactions.insert_one(txn.dict())

                awards_given += 1

            # Update referral status
            await db.referrals.update_one(
                {"id": referral["id"]},
                {
                    "$set": {
                        "status": ReferralStatus.COMPLETED.value,
                        "completed_at": datetime.utcnow(),
                        "reward_applied": True
                    }
                }
            )

            processed_count += 1

    logger.info(f"Processed {processed_count} pending referrals, awarded {awards_given} bonuses")

    return {
        "message": "Pending referrals processed",
        "processed_count": processed_count,
        "awards_given": awards_given
    }


@router.get("/admin/stats")
async def get_admin_referral_stats():
    """Get overall referral program statistics"""
    db = get_db()

    # Aggregate stats from database
    total_codes = await db.referral_codes.count_documents({})
    total_referrals = await db.referrals.count_documents({})
    vendor_referrals = await db.referrals.count_documents({
        "referral_type": ReferralType.VENDOR.value
    })
    customer_referrals = await db.referrals.count_documents({
        "referral_type": ReferralType.CUSTOMER.value
    })

    # Calculate total bonus days awarded
    vendor_stats_cursor = db.vendor_referral_stats.find({})
    total_bonus_days = 0
    async for stat in vendor_stats_cursor:
        total_bonus_days += stat.get("bonus_days_earned", 0)

    # Calculate total Hashi Coins awarded
    customer_stats_cursor = db.customer_reward_accounts.find({})
    total_hashi_coins = 0
    tier_distribution = {"bronze": 0, "silver": 0, "gold": 0, "platinum": 0}

    async for stat in customer_stats_cursor:
        total_hashi_coins += stat.get("total_coins_earned", 0)
        tier = stat.get("tier", "bronze")
        tier_distribution[tier] = tier_distribution.get(tier, 0) + 1

    return {
        "total_referral_codes": total_codes,
        "total_referrals": total_referrals,
        "vendor_referrals": vendor_referrals,
        "customer_referrals": customer_referrals,
        "total_bonus_days_awarded": total_bonus_days,
        "total_hashi_coins_awarded": total_hashi_coins,
        "tier_distribution": tier_distribution
    }
